INSERT INTO hd_gate_wheel (id, gates_count, degrees_per_gate, degrees_per_line, lines_per_gate, offset_degrees, offset_zodiac, offset_note, gate_order, order_by_sign) VALUES (1, 64, 5.625, 0.9375, 6, 358.25, '28°15'' Pisces', 'Gate 25 begins at 358.25 deg absolute (28 deg 15'' Pisces) and wraps the 0/360 (Aries) point.', ARRAY[25,17,21,51,42,3,27,24,2,23,8,20,16,35,45,12,15,52,39,53,62,56,31,33,7,4,29,59,40,64,47,6,46,18,48,57,32,50,28,44,1,43,14,34,9,5,26,11,10,58,38,54,61,60,41,19,13,49,30,55,37,63,22,36]::INT[], '{"Aries": [25, 17, 21, 51, 42, 3], "Taurus": [27, 24, 2, 23, 8, 20], "Gemini": [16, 35, 45, 12, 15, 52], "Cancer": [39, 53, 62, 56], "Leo": [31, 33, 7, 4, 29], "Virgo": [59, 40, 64, 47, 6], "Libra": [46, 18, 48, 57, 32, 50], "Scorpio": [28, 44, 1, 43, 14], "Sagittarius": [34, 9, 5, 26, 11], "Capricorn": [10, 58, 38, 54, 61], "Aquarius": [60, 41, 19, 13, 49, 30], "Pisces": [55, 37, 63, 22, 36], "_note": "Sign buckets are approximate human-readable groupings; some gates straddle a sign boundary. The authoritative position is each gate''s degree_range in the gates section, derived from order + offset. Gate 25 straddles Pisces/Aries."}'::JSONB) ON CONFLICT (id) DO UPDATE SET gates_count = EXCLUDED.gates_count, degrees_per_gate = EXCLUDED.degrees_per_gate, degrees_per_line = EXCLUDED.degrees_per_line, lines_per_gate = EXCLUDED.lines_per_gate, offset_degrees = EXCLUDED.offset_degrees, offset_zodiac = EXCLUDED.offset_zodiac, offset_note = EXCLUDED.offset_note, gate_order = EXCLUDED.gate_order, order_by_sign = EXCLUDED.order_by_sign;
