INSERT INTO hd_settings (key, value, description) VALUES ('planetary_design_calculation_rule', '"The Design moment is the exact time at which the Sun''s ecliptic longitude was 88 deg less than the Personality (birth) Sun longitude. This is approximately 88 days before birth but is NOT a fixed day offset; the engine solves for the exact moment iteratively (the Sun moves ~0.9856 deg/day on average, faster near perihelion in winter, slower near aphelion in summer)."'::JSONB, 'Human Design config: how the Design moment is computed (Sun 88 deg of longitude before birth).') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('planetary_derived_rules', '{"earth": "earth_longitude = (sun_longitude + 180) mod 360", "south_node": "south_node_longitude = (north_node_longitude + 180) mod 360", "profile": "profile = personality.sun.line + ''/'' + design.sun.line", "incarnation_cross_gates": "[personality.sun.gate, personality.earth.gate, design.sun.gate, design.earth.gate]"}'::JSONB, 'Human Design config: derived activation rules (earth, south_node, profile, incarnation_cross_gates).') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('planetary_sides', '["personality", "design"]'::JSONB, 'Human Design config: the two activation sides (personality, design).') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('planetary_bodies_count_per_side', '13'::JSONB, 'Human Design config: number of bodies activated per side.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('type_determination_algorithm', '["1. Compute defined centers from active channels.", "2. hasSacral = Sacral center is defined.", "3. hasMotorToThroat = there exists a path through the defined-channel network from the Throat center to any motor center (Sacral, Heart/Ego, Solar Plexus, Root), found by BFS. Requires Throat to be defined.", "4. If NOT hasSacral AND hasMotorToThroat -> Manifestor.", "5. Else if hasSacral AND hasMotorToThroat -> Manifesting Generator.", "6. Else if hasSacral (and not motor-to-throat) -> Generator.", "7. Else if zero centers are defined -> Reflector.", "8. Otherwise -> Projector (default: defined centers but no defined Sacral and no motor-to-throat)."]'::JSONB, 'Human Design config: ordered decision logic for energy type.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('motor_centers', '["sacral", "heart", "solar", "root"]'::JSONB, 'Human Design config: the motor centers (sacral, heart, solar, root).') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('authority_precedence_order', '["1. Solar Plexus (Emotional) defined -> Emotional Authority.", "2. else Sacral defined -> Sacral Authority.", "3. else Spleen defined -> Splenic Authority.", "4. else Heart/Ego defined -> Ego/Heart Authority.", "5. else G Center defined -> Self-Projected Authority.", "6. else no centers defined -> Lunar Authority (Reflector).", "7. else (remaining defined centers, none of the above) -> Mental/Environmental (no inner authority)."]'::JSONB, 'Human Design config: ordered precedence logic for inner authority.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('definition_algorithm', '"Build an adjacency graph where each channel connects its two centers. Count connected components among the centers that appear in any active channel. components: 0 -> No Definition, 1 -> Single, 2 -> Split, 3 -> Triple Split, 4 -> Quadruple Split."'::JSONB, 'Human Design config: connected-components algorithm for definition type.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('profile_angle_mapping', '{"right": ["1/3", "1/4", "2/4", "2/5", "3/5", "3/6", "4/6"], "left": ["5/1", "5/2", "6/2", "6/3"], "juxtaposition": ["4/1"]}'::JSONB, 'Human Design config: which profiles map to right / left / juxtaposition angles.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('profile_derivation', '"personality_line = line of the Personality (conscious) Sun; design_line = line of the Design (unconscious) Sun. profile string is personality_line + ''/'' + design_line."'::JSONB, 'Human Design config: how the profile string is derived.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('incarnation_cross_gates_rule', '"gates = [Personality Sun gate, Personality Earth gate (= Personality Sun + 180 deg), Design Sun gate, Design Earth gate (= Design Sun + 180 deg)]."'::JSONB, 'Human Design config: the four gates that compose an incarnation cross.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('incarnation_cross_full_name_format', '{"right": "The Right Angle Cross of {name}", "juxtaposition": "The Juxtaposition Cross of {name}", "left": "The Left Angle Cross of {name}"}'::JSONB, 'Human Design config: full-name templates per angle for incarnation crosses.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('incarnation_cross_angle_from_profile', '{"right": ["1/3", "1/4", "2/4", "2/5", "3/5", "3/6", "4/6"], "left": ["5/1", "5/2", "6/2", "6/3"], "juxtaposition": ["4/1"]}'::JSONB, 'Human Design config: profile-to-angle mapping for incarnation crosses.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('centers_classification', '{"motor_centers": ["sacral", "heart", "solar", "root"], "pressure_centers": ["head", "root"], "awareness_centers": ["ajna", "spleen"], "throat_center": "throat", "identity_center": "g"}'::JSONB, 'Human Design config: center classification groupings.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
INSERT INTO hd_settings (key, value, description) VALUES ('metadata', '{"name": "Moon Rhythms Human Design Mechanical Reference", "version": "v1", "generated": "2026-06-23", "system": "human_design", "description": "Single source of truth for the deterministic, structured-lookup mechanical data of the Human Design system used by Moon Rhythms. Mirrors the format of deterministic_data.json (astrology spine). This file is for STRUCTURED LOOKUP and the AI assembler/engine; it does NOT go into the RAG vector database, and it deliberately contains NO long proprietary interpretive prose. Load into Supabase as relational tables and reference from chart calculation and AI prompt assembly.", "primary_extraction_source": "natalengine npm package (src/calculators/humandesign.js and src/data/incarnation-crosses.js) as installed in the moonrhythms.io web app. The app computes Human Design via this library and overrides the definition type with a union-find over channels (pages/api/human-design.api.js).", "design_decisions": {"copyright_boundary": "Human Design''s MECHANICAL structure (gate-to-hexagram mapping, gate-to-center assignments, the 36 channels, 9 centers, 5 types, strategies, 7 authorities, 12 profiles, definition types, incarnation crosses, gate zodiac degree ranges, planetary activations) is factual and is encoded here in full. Long proprietary interpretive descriptions from Jovian Archive or commercial HD books are NOT included. Where a short descriptor appears (theme / keyword / strategy / signature / not-self), it is brief, factual, and in neutral wording carried over from the app''s own data, not lifted prose. Line-level (384) and gate-level interpretive text is intentionally OUT of this file and is a RAG/commissioned-content concern.", "lineage": "Standard Ra Uru Hu / Jovian-lineage mechanics. Where HD sources differ, the Jovian-standard is implemented and alternatives are noted in this file or the research report.", "degree_table_source": "Gate zodiac degree ranges computed deterministically from GATE_ORDER + GATE_WHEEL_OFFSET (358.25 deg = 28 deg 15'' Pisces, where Gate 25 begins) with each gate spanning exactly 5.625 deg (360/64). Cross-checked against published gate-zodiac-degree tables at barneyandflow.com/gate-zodiac-degrees and bonniesorsby.com (accessed 2026-06-23): wheel order, Gate 25 offset, and 5.625 deg span all confirmed. See human_design_RESEARCH.md.", "iching_mapping_source": "HD gate number maps 1:1 to the canonical I Ching (King Wen / Wilhelm-Baynes) hexagram number (Gate N = Hexagram N). Verified against jovianarchive.com, castiching.com, and Wikipedia''s hexagram list (accessed 2026-06-23). hexagram_name carries the natalengine spelling, which matches Wilhelm-Baynes primary titles with only cosmetic variants (e.g. ''Break-through'' for hex 43, ''The Cauldron'' vs archaic ''Caldron'' for hex 50). See human_design_RESEARCH.md.", "type_determination_source": "Type is determined from the set of DEFINED centers (centers connected by at least one fully-defined channel), via the rules in natalengine humandesign.js: motor-to-throat connectivity (BFS over the defined-channel network) plus defined-Sacral state. Encoded verbatim in types[].determination_rule and type_determination_algorithm.", "authority_determination_source": "Authority is assigned by strict precedence over defined centers (Emotional/Solar Plexus > Sacral > Splenic > Ego/Heart > Self/G > None/Mental > Lunar), per natalengine determineAuthority(). Encoded in authorities[].precedence and authority_precedence_order.", "definition_taxonomy_source": "Definition type is the number of connected components among defined centers (union-find / BFS over channel-connected centers): 1=Single, 2=Split, 3=Triple Split, 4=Quadruple Split, 0=No Definition. This matches the app''s override in pages/api/human-design.api.js (calculateDefinition). NOTE: the bundled natalengine humandesign.js uses a cruder channel-COUNT heuristic for definition; the app override (component-count) is the correct mechanic and is the one encoded here.", "planetary_activations": "13 bodies per side (Personality/conscious at birth, Design/unconscious ~88 deg of solar arc before birth). Earth = Sun + 180 deg; South Node = North Node + 180 deg. The Design moment is the exact time when the Sun was 88 deg of ecliptic longitude before its birth position (natalengine solves this iteratively, not a fixed 88-day offset).", "verification_conflicts": "None material. Gate->hexagram numbering, wheel order, Gate 25 offset, 5.625 deg span, 6 lines per gate, and the 6 line-name archetypes were all confirmed across >=2 reputable sources. Only cosmetic naming variants exist (documented above). The line value 0.9375 deg/line was not found printed verbatim in a source but is arithmetically forced by 5.625/6 and is internally consistent."}, "counts": {"centers": 9, "gates": 64, "channels": 36, "types": 5, "authorities": 7, "profiles": 12, "lines": 6, "definition_types": 5, "planetary_activations_per_side": 13, "incarnation_cross_gate_index": 64, "incarnation_cross_named_per_gate": 3}}'::JSONB, 'Human Design config: source metadata, counts, and design decisions from the spine JSON.') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW();
